    public Position build() {

      return new Position(
          accountId,
          adjustedSettled,
          adjustedTrade,
          assetId,
          correspondentId,
          date,
          fpsl,
          free,
          lastAdjustedDate,
          name,
          pendingDrip,
          pendingOutgoingAcat,
          pendingWithdrawal,
          positionVersion,
          settled,
          trade,
          unrestricted);
    }
